//! D.PEEL.OBJECT.1 — Middle peel on the object manifold.
//!
//! Operates on n spatial clusters (n ~ 3-20 for ARC).
//! Searches for the spatial transformation: which object moves where.
//! Scoring: object-level cocycle residual in Z. O(n³).
//! Fed by touch sense (adjacency, clusters, Betti numbers).
//! Constrained by T_value from the outer (value) peel.
//!
//! The middle shell of the nested peel architecture.
//! Its output (T_spatial) constrains the inner peel (cell manifold).

use super::super::vocabulary::*;
use crate::perception;

/// Result of the object-level peel.
#[derive(Debug, Clone)]
pub struct ObjectPeelResult {
    /// Per-object mapping: source cluster index → target cluster index.
    /// None means the object had no match.
    pub object_map: Vec<(usize, Option<usize>)>,
    /// Cocycle residual of the spatial transformation in Z.
    pub cocycle_residual: i64,
    /// Torsion order of the spatial transformation.
    /// Rotation90 = order 4. Reflection = order 2. Translation = order 1 (aperiodic).
    /// Identity = order 1.
    pub torsion_order: u16,
    /// Which thought achieved this result.
    pub best_thought: Thought,
    /// How many thoughts were evaluated.
    pub thoughts_evaluated: u32,
    /// The transformed pairs after applying the best spatial thought.
    pub transformed_pairs: Vec<(Vec<i64>, Vec<i64>)>,
    /// The transformed test input.
    pub transformed_test: Option<Vec<i64>>,
}

/// Measure the torsion order of a spatial thought.
/// The inherent period of the transformation group element.
fn measure_spatial_torsion(thought: &Thought) -> u16 {
    match thought {
        Thought::Identity => 1,
        Thought::Rotate90 => 4,
        Thought::Rotate180 => 2,
        Thought::Rotate270 => 4,
        Thought::ReflectVertical | Thought::ReflectHorizontal => 2,
        Thought::Translate(_, _) => 1, // aperiodic on infinite grid, 1 on finite (wraps)
        Thought::Compose(a, b) => {
            // lcm of component torsion orders
            let ta = measure_spatial_torsion(a) as u64;
            let tb = measure_spatial_torsion(b) as u64;
            let (mut x, mut y) = (ta, tb);
            while y != 0 { let t = y; y = x % y; x = t; }
            (ta / x * tb).min(256) as u16
        }
        _ => 1,
    }
}

/// Peel the object manifold: find the spatial transformation between clusters.
///
/// Uses the value map from the outer peel to identify which clusters in the
/// candidate correspond to which clusters in the target. Then searches
/// the object vocabulary (Rotate, Reflect, Translate) for the thought
/// that best reproduces the spatial relationships.
///
/// Scoring is the cocycle residual of the object-level Delta — the
/// relational structure between cluster centroids. O(n³) where n = clusters.
pub fn peel_object_manifold(
    train_pairs: &[(Vec<i64>, Vec<i64>)],
    test_input: Option<&[i64]>,
    rows: usize,
    cols: usize,
    _value_map: &[(i64, i64)],
    touch_source: &perception::AdjacencyStructure,
    touch_target: &perception::AdjacencyStructure,
    genomic_spatial_ops: &[crate::engine::ComposedOperator],
) -> ObjectPeelResult {
    // Extract foreground clusters from target (non-background)
    let bg = touch_target.clusters.iter()
        .max_by_key(|c| c.cell_indices.len())
        .map(|c| c.value).unwrap_or(0);

    let target_objects: Vec<&perception::CohesionCluster> = touch_target.clusters.iter()
        .filter(|c| c.value != bg && !c.cell_indices.is_empty())
        .collect();

    let source_objects: Vec<&perception::CohesionCluster> = touch_source.clusters.iter()
        .filter(|c| c.value != bg && !c.cell_indices.is_empty())
        .collect();

    let n_obj = target_objects.len().max(source_objects.len());

    // Build target object properties: centroid (row, col), value, mass
    let obj_props = |objs: &[&perception::CohesionCluster]| -> Vec<(i64, i64, i64, i64)> {
        objs.iter().map(|c| {
            let (mr, mc, _, _) = c.bbox;
            (mr as i64, mc as i64, c.value, c.cell_indices.len() as i64)
        }).collect()
    };

    let target_props = obj_props(&target_objects);
    let _source_props = obj_props(&source_objects);

    // Cocycle residual on object properties: measure relational consistency
    // of (dr, dc) displacement between object pairs
    let measure_object_cocycle = |candidate_props: &[(i64, i64, i64, i64)]| -> i64 {
        let n = candidate_props.len().min(target_props.len());
        let mut residual = 0i64;
        for i in 0..n {
            for j in 0..n {
                if j == i { continue; }
                for ki in 0..n {
                    if ki == i || ki == j { continue; }
                    // Delta = row difference between objects
                    let t_ik = target_props[ki].0 - target_props[i].0;
                    let t_ij = target_props[j].0 - target_props[i].0;
                    let t_jk = target_props[ki].0 - target_props[j].0;
                    let c_ik = candidate_props[ki].0 - candidate_props[i].0;
                    let c_ij = candidate_props[j].0 - candidate_props[i].0;
                    let c_jk = candidate_props[ki].0 - candidate_props[j].0;
                    let d_ik = c_ik - t_ik;
                    let d_ij = c_ij - t_ij;
                    let d_jk = c_jk - t_jk;
                    residual += (d_ik - d_ij - d_jk).abs();

                    // Also column dimension
                    let t_ik = target_props[ki].1 - target_props[i].1;
                    let t_ij = target_props[j].1 - target_props[i].1;
                    let t_jk = target_props[ki].1 - target_props[j].1;
                    let c_ik = candidate_props[ki].1 - candidate_props[i].1;
                    let c_ij = candidate_props[j].1 - candidate_props[i].1;
                    let c_jk = candidate_props[ki].1 - candidate_props[j].1;
                    let d_ik = c_ik - t_ik;
                    let d_ij = c_ij - t_ij;
                    let d_jk = c_jk - t_jk;
                    residual += (d_ik - d_ij - d_jk).abs();
                }
            }
        }
        residual
    };

    // Build vocabulary: spatial thoughts + genomic spatial operators
    let mut vocab = object_vocabulary(rows, cols);
    for op in genomic_spatial_ops {
        vocab.push(Thought::Genomic {
            opcode: op.opcode,
            parameter: op.parameter,
            sigma: op.sigma.clone(),
        });
    }

    let mut best = ObjectPeelResult {
        object_map: (0..n_obj).map(|i| (i, Some(i))).collect(),
        cocycle_residual: i64::MAX,
        torsion_order: 1,
        best_thought: Thought::Identity,
        thoughts_evaluated: 0,
        transformed_pairs: train_pairs.to_vec(),
        transformed_test: test_input.map(|t| t.to_vec()),
    };

    for thought in &vocab {
        // Apply spatial thought to all training inputs
        let new_pairs: Vec<(Vec<i64>, Vec<i64>)> = train_pairs.iter()
            .map(|(inp, out)| (thought.apply_to_values(inp, rows, cols), out.clone()))
            .collect();

        let new_test = test_input.map(|t| thought.apply_to_values(t, rows, cols));

        // Extract object properties from the transformed grid
        let cand_touch = perception::compute_adjacency_structure(&new_pairs[0].0, rows, cols);
        let cand_objects: Vec<&perception::CohesionCluster> = cand_touch.clusters.iter()
            .filter(|c| c.value != bg && !c.cell_indices.is_empty())
            .collect();
        let cand_props = obj_props(&cand_objects);

        let residual = measure_object_cocycle(&cand_props);
        best.thoughts_evaluated += 1;

        // C(T) selects — object cocycle residual is primary.
        // When cocycle ties (common with <3 objects), use cell-level L1
        // as tiebreaker. The thought that produces lower L1 against the
        // target wins, even if the object cocycle is tied.
        let l1: u64 = new_pairs.iter().map(|(inp, out)| {
            inp.iter().zip(out.iter()).map(|(a, b)| (a - b).unsigned_abs()).sum::<u64>()
        }).sum();
        let best_l1: u64 = best.transformed_pairs.iter().map(|(inp, out)| {
            inp.iter().zip(out.iter()).map(|(a, b)| (a - b).unsigned_abs()).sum::<u64>()
        }).sum();

        (residual < best.cocycle_residual || (residual == best.cocycle_residual && l1 < best_l1)).then(|| {
            best.cocycle_residual = residual;
            best.torsion_order = measure_spatial_torsion(thought);
            best.best_thought = thought.clone();
            best.transformed_pairs = new_pairs.clone();
            best.transformed_test = new_test.clone();
        });
    }

    best
}
